import React, { useState } from "react";

function Evaluation() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule6 = async () => {
    setLoading(true);
    try {
      const res = await fetch("http://127.0.0.1:5000/module6");
      const data = await res.json();
      setResult(data);
    } catch (e) {
      console.error(e);
      alert("Backend error");
    }
    setLoading(false);
  };

  const MetricsBlock = ({ title, m }) => (
    <div style={{ margin: "10px", padding: "10px", border: "1px solid #ccc" }}>
      <h3>{title}</h3>
      <p>TPR: {m.TPR.toFixed(2)}%</p>
      <p>FNR: {m.FNR.toFixed(2)}%</p>
      <p>FPR: {m.FPR.toFixed(2)}%</p>
      <p>TNR: {m.TNR.toFixed(2)}%</p>
      <p>F1 Score: {(m.F1 * 100).toFixed(2)}%</p>
      <p>
        Confusion → TN: {m.confusion.tn} | FP: {m.confusion.fp} | FN: {m.confusion.fn} | TP: {m.confusion.tp}
      </p>
    </div>
  );

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Module 6: Evaluation & Metrics</h2>

      <button onClick={runModule6}>Run Module 6</button>
      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div>
          <h3>Total Samples: {result.test_size}</h3>

          {/* 🔹 Metrics */}
          <div style={{ display: "flex", justifyContent: "center", gap: "20px", flexWrap: "wrap" }}>
            <MetricsBlock title="OCSVM" m={result.ocsvm.metrics} />
            <MetricsBlock title="DBSCAN" m={result.dbscan.metrics} />
          </div>

          {/* 🔹 Full Table */}
          <h3>Full Comparison Table</h3>
          <div style={{ height: "500px", overflowY: "scroll", border: "1px solid black" }}>
            <table border="1" width="100%">
              <thead>
                <tr>
                  <th>Index</th>
                  <th>Actual</th>
                  <th>OCSVM</th>
                  <th>DBSCAN</th>
                </tr>
              </thead>
              <tbody>
                {result.actual.map((val, i) => (
                  <tr key={i}>
                    <td>{i}</td>
                    <td>{val}</td>
                    <td>{result.ocsvm.predictions[i]}</td>
                    <td>{result.dbscan.predictions[i]}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

        </div>
      )}
    </div>
  );
}

export default Evaluation;
